SELECT "INEV" AS LineStatus, Item.[Trademark Code], Item.[Collection Code], Item.[Season Code], Item.[Line Code] AS LineCode, Item.[Product Family], Item.[Product Sex], Item.[Model Item No_] AS Article, [Purchase Line].[Variable Code 01] AS Color, [Purchase Line].[Promised Receipt Date] AS PromisedReceiptDate, [Purchase Line].[Requested Receipt Date] AS RequestedReceiptDate, [Purchase Line].[Planned Receipt Date] AS PlannedReceiptDate, Date() AS ReceiptDate, "XXX" AS ReceiptNumber, [Purchase Line].[Document No_] AS OrderNumber, [Purchase Line].[Line No_] AS OrderLine, [Purchase Header].[Vendor Order No_] AS VendorOrderNr, AnalisiDateConsegnaDatoAssortimenti.AssortmentCode, Val([outstanding quantity]) AS ReceiptQuantity, Val([Purchase Line.Line Amount])/Val([Purchase Line.quantity])*Val([Purchase Line.outstanding quantity]) AS ReceiptValue, [Purchase Line].[Document Type], [Purchase Line].[Delete Reason], Item.[Description 2], [Purchase Line].[Sales_Purchase Status Code] AS CodStatusVendAcq, [Purchase Line].[Sales_Purchase Status - Item] AS CodStatusVendAcqArticolo, Item.[Sold Out], Item.[Sold Out Date], Item.[Sales_Purchase Status Date], "" AS [Vendor Shipment No_], Item.Manufacturer AS ManufacturerCode, Item.[advertising material]
FROM (([Purchase Line] INNER JOIN Item ON [Purchase Line].No_ = Item.No_) INNER JOIN AnalisiDateConsegnaDatoAssortimenti ON ([Purchase Line].[Original Line No_] = AnalisiDateConsegnaDatoAssortimenti.[Line No_]) AND ([Purchase Line].[Document No_] = AnalisiDateConsegnaDatoAssortimenti.[Document No_])) INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_
WHERE (((Item.[Season Code])=[filtroStagione]) AND ((Val([outstanding quantity]))<>0) AND (([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=2));

